import React, { useState } from 'react';
import styles from './TheEditSection.module.css';

const mensProducts = [
  {
    id: 1,
    name: 'CROSSBODY BAG (STONE)',
    price: '289,000 KRW',
    bg: '#dddad3',
    imgBg: '#c4c1ba',
    showHover: false,
  },
  {
    id: 2,
    name: 'LAPEL JACKET (BLACK)',
    price: '315,000 KRW',
    bg: '#e0ddd6',
    imgBg: '#2a2a2a',
    showHover: false,
  },
  {
    id: 3,
    name: 'WIDE LEG TROUSERS (GREY)',
    price: '198,000 KRW',
    bg: '#d5d2cb',
    imgBg: '#b0ada6',
    showHover: false,
  },
];

function ProductCard({ product }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      className={styles.card}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div className={styles.imageWrap} style={{ background: product.bg }}>
        <div className={styles.productShape} style={{ background: product.imgBg }} />
        {product.showHover && (
          <div className={`${styles.hoverOverlay} ${hovered ? styles.hoverVisible : ''}`}>
            <p className={styles.hoverName}>{product.name}</p>
            <p className={styles.hoverPrice}>{product.price}</p>
          </div>
        )}
      </div>
      {!product.showHover && (
        <div className={styles.meta}>
          <p className={styles.name}>{product.name}</p>
          <p className={styles.price}>{product.price}</p>
        </div>
      )}
    </div>
  );
}

function MensEditSection() {
  return (
    <section className={styles.section}>
      <div className={styles.sectionHeader}>
        <h2 className={styles.sectionTitle}>THE EDIT</h2>
        <a href="#!" className={styles.viewAll}>view all</a>
      </div>
      <div className={styles.grid}>
        {mensProducts.map((product) => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>
      <div className={styles.dots}>
        <span className={`${styles.dot} ${styles.dotActive}`} />
        <span className={styles.dot} />
        <span className={styles.dot} />
      </div>
    </section>
  );
}

export default MensEditSection;
